import { Injectable, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { Role, User } from '../models';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'user';

/**
 * EasyFile authentication state. Single clean implementation.
 * Persists the JWT under `auth_token`. Exposes `isAdmin` for the role guard.
 *
 * NOTE: this mockup stubs login/signup locally so the full authenticated UI is
 * reviewable without a live backend. `service_agent` replaces the stubbed bodies
 * with real /auth/login and /auth/signup calls.
 */
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly _user = signal<User | null>(this.restoreUser());

  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => this._user() !== null);
  readonly isAdmin = computed(() => this._user()?.role === 'admin');

  constructor(private router: Router) {}

  hasRole(...roles: Role[]): boolean {
    const r = this._user()?.role;
    return r ? roles.includes(r) : false;
  }

  login(email: string, _password: string): void {
    const role: Role = email.startsWith('admin') ? 'admin' : 'filer';
    this.persist({ id: 'me', email, name: email.split('@')[0], role }, 'mock-jwt-token');
    this.router.navigate(['/returns']);
  }

  signup(name: string, email: string, _password: string): void {
    // First-ever user becomes admin server-side; mockup treats new signups as filers.
    this.persist({ id: 'me', email, name, role: 'filer' }, 'mock-jwt-token');
    this.router.navigate(['/returns']);
  }

  /** Demo Mode bypass — logs in as an admin filer so reviewers can inspect all screens. */
  demoLogin(): void {
    const user: User = {
      id: 'demo-admin',
      email: 'admin@easyfile.dev',
      name: 'Demo Admin',
      role: 'admin',
    };
    this.persist(user, 'demo-admin-token');
    localStorage.setItem('access_token', 'demo-admin-token');
    localStorage.setItem('isAuthenticated', 'true');
    this.router.navigate(['/returns']);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem('access_token');
    localStorage.removeItem('isAuthenticated');
    localStorage.removeItem(USER_KEY);
    this._user.set(null);
    this.router.navigate(['/login']);
  }

  private persist(user: User, token: string): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._user.set(user);
  }

  private restoreUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }
}
